@startuml
title Combat Subsystem Class Diagram

class "CombatManager" {
  +C
}

class "Player" {
  +C
}

class "Combat" {
  +C
  Combatants allies
  Combatants enemies
  Inventory reward
  Move playerMove
  Move npcMove
  turn()
}

class "Move" {
  +C
  String name
  int blockPercent
  double damage
  double healing
}

class "Combatants" {
  +C
}

class "Inventory" {
  +C
}

class "Entity" {
  +C
}

"CombatManager" *-- "Combat" : aggregation
"Combat" o-- "Player" : 0..*
"Combat" *-- "Move" : 2
"Combat" o-- "Combatants" : 2
"Combat" *-- "Inventory" : 1
"Combatants" o-- "Entity" : 0..*

note bottom
  Authored: Mason Fabel
  Reviewed: Casey Blair
  External Classes: Entity, Inventory, Player
end note

@enduml
